form:Form.form:Scripts:
		function LoadForm()
{
	ONLOAD();
	if (Ctrl("tipo").GetXValue()=="R")
	{		
		ChangeHorarioNuevo();	
	}
	else
	{
		Ctrl("oi_escuadra_nuevo").SetEnabled(false);
	}          	
}

function Ejecutar()
{ 
 	if (Ctrl('f_fin').GetXValue() != "" && Ctrl('f_inicio').TypedValue() > Ctrl('f_fin').TypedValue())
	{
		alert("La Fecha Inicio debe ser anterior o igual a la Fecha Fin");
		return false;
	}
 	if (Ctrl("list2").TotalRowsCount()==0)
 	{             
 		alert("No hay legajos filtrados.");
 		return false;
 	}

 	Ctrl('legajos').DelAllRow();
 	for (key in arrB) Ctrl('legajos').AddRow().SetAttr('id', key.substr(1));

	Ctrl("main").DoEvent("FILTER");
}

function ValidateEscuadra()
{
	if (Ctrl("tipo").GetXValue()=="R")
	{ //es rotativo
		if (Ctrl("oi_escuadra_nuevo").GetXValue()=="")
		{
			Ctrl("oi_escuadra_nuevo").SetError("La escuadra es requerida en horarios Rotativos.");
			return false;
		}
	}
	return true;
}

function ChangeHorarioNuevo()
{	
	var param = "<HORARIO id=\""+Ctrl("oi_horario_nuevo").GetXValue()+"\"/>";	                                                                                      	
	var Escuadras;	
	Escuadras=GetProxy().SQLService().GetOBJ(Ctrl("main").getResource("ESCUADRAS"),param);			
	Ctrl("oi_escuadra_nuevo").SetEnabled(Ctrl("tipo").GetXValue()=="R");	
	Ctrl("oi_escuadra_nuevo").setOptions(Escuadras.associatedELE);	
	Ctrl("oi_escuadra_nuevo").SetXValue("");	
}
